/** Generates an SVG preview based on the template's layer layout */
function TemplateSVGPreview({ template }: { template: Template }) {
  const W = 280
  const H = Math.round(W * (template.height / template.width))
  const clampH = Math.min(H, 220)
  const scaleX = W / template.width
  const scaleY = clampH / template.height
  const bg = template.background_color || "#1a1a2e"

  return (
    <svg width={W} height={clampH} viewBox={`0 0 ${W} ${clampH}`} xmlns="http://www.w3.org/2000/svg" style={{ display: "block" }}>
      <rect width={W} height={clampH} fill={bg} />
      {(template.layers || []).map((layer, i) => {
        const x = Math.round((layer.x || 0) * scaleX)
        const y = Math.round((layer.y || 0) * scaleY)
        const w = Math.round((layer.width || 100) * scaleX)
        const h = Math.round((layer.height || 50) * scaleY)
        if (layer.type === "image" && w > 0 && h > 0) {
          const opacity = layer.opacity ?? 1
          return (
            <g key={i} opacity={opacity}>
              <rect x={x} y={y} width={w} height={h} fill="rgba(255,255,255,0.1)" rx={4} />
              <line x1={x} y1={y} x2={x + w} y2={y + h} stroke="rgba(255,255,255,0.15)" strokeWidth={1} />
              <line x1={x + w} y1={y} x2={x} y2={y + h} stroke="rgba(255,255,255,0.15)" strokeWidth={1} />
            </g>
          )
        }
        if (layer.type === "text") {
          const fs = Math.max(6, Math.round((layer.font_size || 48) * scaleX * 0.8))
          const clampedY = Math.min(y, clampH - fs - 2)
          return (
            <text key={i} x={x} y={clampedY + fs} fill={layer.color || "#FFFFFF"} fontSize={fs} fontWeight="bold" fontFamily="Arial" clipPath={`url(#clip${i})`}>
              {layer.text?.substring(0, 20) || ""}
            </text>
          )
        }
        return null
      })}
      {/* Category badge */}
      {template.category && (
        <>
          <rect x={6} y={clampH - 22} width={60} height={16} rx={8} fill={CATEGORY_COLORS[template.category] || "#6366f1"} opacity={0.9} />
          <text x={36} y={clampH - 10} textAnchor="middle" fill="#fff" fontSize={8} fontFamily="Arial">{template.category.toUpperCase()}</text>
        </>
      )}
    </svg>
  )
}

export default function TemplatesPage() {
  const [templates, setTemplates] = useState<Template[]>([])
  const [loading, setLoading] = useState(true)
  const [applying, setApplying] = useState<string | null>(null)
  const [searchQuery, setSearchQuery] = useState("")
  const [activeCategory, setActiveCategory] = useState("all")
  const [previewTemplate, setPreviewTemplate] = useState<Template | null>(null)
  const [applied, setApplied] = useState<string | null>(null)
  const router = useRouter()
  const { toast } = useToast()

  useEffect(() => { loadTemplates() }, [])

  const loadTemplates = async () => {
    setLoading(true)
    try {
      const res = await fetch(`${API_BASE}/templates`)
      if (!res.ok) throw new Error("Failed")
      const data = await res.json()
      setTemplates(data.templates || [])
    } catch {
      // Use built-in demo templates as fallback
      setTemplates(DEMO_TEMPLATES)
    } finally {
      setLoading(false)
    }
  }

  const reseedTemplates = async () => {
    setLoading(true)
    try {
      await fetch(`${API_BASE}/templates/reseed`, { method: "POST" })
      await loadTemplates()
      toast({ title: "Templates reseeded!" })
    } catch (e: any) {
      toast({ title: "Reseed failed", description: e.message, variant: "destructive" })
    } finally {
      setLoading(false)
    }
  }

  const handleUseTemplate = async (template: Template) => {
    setApplying(template.template_id)
    try {
      // Create project first
      const params = new URLSearchParams({ width: String(template.width), height: String(template.height), background_color: template.background_color || "#FFFFFF" })
      const projRes = await fetch(`${API_BASE}/editor/create-project?${params}`, { method: "POST" })
      const projData = await projRes.json()
      const projectId = projData.project_id

      // Apply template
      await fetch(`${API_BASE}/editor/${projectId}/apply-template/${template.template_id}`, { method: "POST" })

      // Save to localStorage
      const saved = JSON.parse(localStorage.getItem("retailor_projects") || "[]")
      saved.push({ id: projectId, name: `${template.template_name} — ${new Date().toLocaleDateString()}`, status: "active", createdAt: new Date().toISOString(), assetsCount: template.layers_count || 0, progress: 20 })
      localStorage.setItem("retailor_projects", JSON.stringify(saved))

      setApplied(template.template_id)
      toast({ title: "Template Applied!", description: "Opening editor..." })
      setTimeout(() => router.push("/editor"), 800)
    } catch (e: any) {
      toast({ title: "Failed", description: e.message, variant: "destructive" })
    } finally {
      setApplying(null)
    }
  }

  const categories = ["all", ...Array.from(new Set(templates.map(t => t.category).filter(Boolean)))]

  const filtered = templates.filter(t => {
    const matchesSearch = t.template_name.toLowerCase().includes(searchQuery.toLowerCase()) ||
      (t.tags || []).some(tag => tag.toLowerCase().includes(searchQuery.toLowerCase()))
    const matchesCategory = activeCategory === "all" || t.category === activeCategory
    return matchesSearch && matchesCategory
  })

  return (
    <div className="flex h-full flex-col">
      {/* Header */}
      <div className="border-b border-border bg-card px-8 py-6">
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-3xl font-bold tracking-tight">Template Library</h1>
            <p className="mt-1 text-muted-foreground">12 professional designs across 7 categories — click to apply instantly</p>
          </div>
          <div className="flex gap-2">
            <Button variant="outline" size="sm" onClick={reseedTemplates} disabled={loading} className="gap-2 bg-transparent">
              <RefreshCw className={`h-4 w-4 ${loading ? "animate-spin" : ""}`} /> Reseed
            </Button>
          </div>
        </div>

        {/* Search */}
        <div className="mt-4 flex gap-3 max-w-xl">
          <div className="relative flex-1">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
            <Input placeholder="Search templates or tags..." className="pl-9 h-10" value={searchQuery} onChange={e => setSearchQuery(e.target.value)} />
          </div>
        </div>

        {/* Category Tabs */}
        <div className="mt-3 flex gap-2 flex-wrap">
          {categories.map(cat => (
            <button
              key={cat}
              onClick={() => setActiveCategory(cat)}
              className={`px-3 py-1 rounded-full text-xs font-medium transition-all ${activeCategory === cat ? "text-white shadow-sm" : "bg-muted text-muted-foreground hover:bg-muted/80"}`}
              style={activeCategory === cat ? { background: CATEGORY_COLORS[cat] || "#6366f1" } : {}}
            >
              {CATEGORY_LABELS[cat] || cat}
            </button>
          ))}
        </div>
      </div>

      {/* Grid */}
      <ScrollArea className="flex-1">
        <div className="p-8">
          {loading ? (
            <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-6">
              {Array.from({ length: 8 }).map((_, i) => (
                <div key={i} className="rounded-xl bg-muted animate-pulse" style={{ height: 260 }} />
              ))}
            </div>
          ) : filtered.length === 0 ? (
            <div className="text-center py-20 text-muted-foreground">
              <LayoutTemplate className="h-16 w-16 mx-auto mb-4 opacity-20" />
              <p className="text-lg font-medium">No templates found</p>
              <p className="text-sm mt-1">Try a different search or category</p>
            </div>
          ) : (
            <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-6">
              {filtered.map(template => (
                <Card key={template.template_id} className="overflow-hidden group cursor-pointer hover:ring-2 hover:ring-primary/50 transition-all duration-200">
                  {/* Preview */}
                  <div className="relative overflow-hidden bg-muted/30" onClick={() => setPreviewTemplate(template)}>
                    <TemplateSVGPreview template={template} />
                    <div className="absolute inset-0 bg-black/0 group-hover:bg-black/20 transition-colors flex items-center justify-center">
                      <Eye className="h-8 w-8 text-white opacity-0 group-hover:opacity-100 transition-opacity" />
                    </div>
                    {applied === template.template_id && (
                      <div className="absolute inset-0 bg-green-500/20 flex items-center justify-center">
                        <CheckCircle className="h-10 w-10 text-green-500" />
                      </div>
                    )}
                  </div>

                  {/* Info */}
                  <CardContent className="p-3">
                    <p className="font-semibold text-sm leading-tight">{template.template_name}</p>
                    <p className="text-xs text-muted-foreground mt-0.5">{template.width}×{template.height}px</p>
                    <div className="flex flex-wrap gap-1 mt-2">
                      {(template.tags || []).slice(0, 3).map(tag => (
                        <Badge key={tag} variant="secondary" className="text-[10px] px-1.5 py-0">{tag}</Badge>
                      ))}
                    </div>
                    <Button
                      className="w-full mt-3 h-8 text-xs gradient-primary"
                      onClick={() => handleUseTemplate(template)}
                      disabled={applying === template.template_id}
                    >
                      {applying === template.template_id ? <RefreshCw className="h-3 w-3 animate-spin mr-1" /> : null}
                      {applying === template.template_id ? "Applying..." : "Use Template →"}
                    </Button>
                  </CardContent>
                </Card>
              ))}
            </div>
          )}
        </div>
      </ScrollArea>

      {/* Preview Dialog */}
      <Dialog open={!!previewTemplate} onOpenChange={v => !v && setPreviewTemplate(null)}>
        <DialogContent className="max-w-2xl">
          <DialogHeader>
            <DialogTitle>{previewTemplate?.template_name}</DialogTitle>
            <DialogDescription>
              {previewTemplate?.width}×{previewTemplate?.height}px • {previewTemplate?.layers_count || 0} layers • {CATEGORY_LABELS[previewTemplate?.category || ""] || previewTemplate?.category}
            </DialogDescription>
          </DialogHeader>
          {previewTemplate && (
            <div className="space-y-4">
              <div className="flex items-center justify-center bg-muted/30 rounded-xl p-6">
                <TemplateSVGPreview template={previewTemplate} />
              </div>
              <div className="flex gap-2 flex-wrap">
                {(previewTemplate.tags || []).map(tag => <Badge key={tag} variant="outline">{tag}</Badge>)}
              </div>
              <div className="grid grid-cols-3 gap-3 text-center text-sm text-muted-foreground">
                <div className="border rounded-lg p-3"><p className="font-semibold text-foreground">{previewTemplate.width}px</p><p>Width</p></div>
                <div className="border rounded-lg p-3"><p className="font-semibold text-foreground">{previewTemplate.height}px</p><p>Height</p></div>
                <div className="border rounded-lg p-3"><p className="font-semibold text-foreground">{previewTemplate.layers_count || 0}</p><p>Layers</p></div>
              </div>
              <Button className="w-full gradient-primary h-11" onClick={() => { handleUseTemplate(previewTemplate); setPreviewTemplate(null) }}
                disabled={applying === previewTemplate.template_id}>
                Use This Template →
              </Button>
            </div>
          )}
        </DialogContent>
      </Dialog>
    </div>
  )
}

